def _int_to_bytes(i: int) -> bytes:
    return i.to_bytes(8, "big")

def totp_code(secret: bytes, for_time: int = None, step: int = 30, digits: int = 6) -> str:
    if for_time is None:
        for_time = int(time.time())
    counter = for_time // step
    msg = _int_to_bytes(counter)
    h = hmac.new(secret, msg, hashlib.sha1).digest()
    o = h[-1] & 0x0F
    dbc = int.from_bytes(h[o:o+4], "big") & 0x7FFFFFFF
    code = dbc % (10 ** digits)
    return str(code).zfill(digits)

def verify_totp(secret: bytes, code: str, window: int = 1, step: int = 30, digits: int = 6) -> bool:
    code = (code or "").strip()
    if not code.isdigit() or len(code) != digits:
        return False
    now = int(time.time())
    for w in range(-window, window + 1):
        if hmac.compare_digest(totp_code(secret, now + w * step, step=step, digits=digits), code):
            return True
    return False

